import requests

try:
    # Attempt to fetch a non-existent category ID (99999) from Northwind API
    resp = requests.get("https://northwind.vercel.app/api/categories/99999", timeout=5)
    resp.raise_for_status()       # Raises HTTPError if status is 4xx/5xx
    data = resp.json()
except requests.exceptions.Timeout:
    print("Request timed out")
except requests.exceptions.HTTPError as e:
    print(f"HTTP error occurred (expected): {e}")
except requests.exceptions.RequestException as e:
    print(f"Ambiguous request failed: {e}")
